-- 4a. About Company Page
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('page', 'about-company',
 'تقديم الشركة',
 'À propos de la société',
 'About the Company',
 'شركة البيئة والغراسة والبستنة بقابس شركة تابعة للمجمع الكيميائي التونسي، تأسست في 15 أفريل 2011.',
 'Société d\'Environnement, Plantation et Jardinage de Gabès, filiale du Groupe Chimique Tunisien, créée le 15 avril 2011.',
 'Environment, Plantation and Gardening Company of Gabès, a subsidiary of the Tunisian Chemical Group, established on April 15, 2011.',
 '<h2>تقديم الشركة</h2><p>شركة البيئة والغراسة والبستنة بقابس هي شركة تابعة للمجمع الكيميائي التونسي. تأسست الشركة في 15 أفريل 2011 وتم نشرها في الرائد الرسمي للجمهورية التونسية في 15 نوفمبر 2011.</p><p>يمتلك المجمع الكيميائي التونسي حوالي 99% من رأس مال الشركة.</p><h3>مجالات النشاط</h3><ul><li>البيئة والتنمية المستدامة</li><li>الغراسة والبستنة</li><li>المساهمة في التنمية المحلية</li><li>التشغيل والتدريب</li></ul>',
 '<h2>Présentation de la société</h2><p>La Société d\'Environnement, Plantation et Jardinage de Gabès est une filiale du Groupe Chimique Tunisien. La société a été créée le 15 avril 2011 et publiée au Journal Officiel de la République Tunisienne le 15 novembre 2011.</p><p>Le Groupe Chimique Tunisien détient environ 99% du capital de la société.</p><h3>Domaines d\'activité</h3><ul><li>Environnement et développement durable</li><li>Plantation et jardinage</li><li>Contribution au développement local</li><li>Emploi et formation</li></ul>',
 '<h2>About the Company</h2><p>The Environment, Plantation and Gardening Company of Gabès is a subsidiary of the Tunisian Chemical Group. The company was established on April 15, 2011 and was published in the Official Gazette of the Republic of Tunisia on November 15, 2011.</p><p>The Tunisian Chemical Group owns approximately 99% of the company\'s capital.</p><h3>Areas of Activity</h3><ul><li>Environment and sustainable development</li><li>Plantation and gardening</li><li>Contribution to local development</li><li>Employment and training</li></ul>',
 'published', 1, NOW(), NOW());

-- 4b. Director Message Page
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('page', 'director-message',
 'كلمة السيد المدير العام',
 'Mot du Directeur Général',
 'Director\'s Message',
 'كلمة السيد عبد السلام بسيسة، المدير العام لشركة البيئة والغراسة والبستنة بقابس.',
 'Mot de M. Abdel Salam Besisse, Directeur Général de la Société d\'Environnement, Plantation et Jardinage de Gabès.',
 'Message from Mr. Abdel Salam Besisse, General Director of the Environment, Plantation and Gardening Company of Gabès.',
 '<h2>كلمة السيد المدير العام</h2><p>بسم الله الرحمن الرحيم</p><p>السيدات والسادة،</p><p>يسعدني أن أرحب بكم في الموقع الرسمي لشركة البيئة والغراسة والبستنة بقابس.</p><p>إن شركتنا، التابعة للمجمع الكيميائي التونسي، تعمل منذ تأسيسها في 15 أفريل 2011 على تحقيق أهدافها في مجال البيئة والتنمية المستدامة بجهة ڨابس.</p><p>نعمل جاهدين للوصول إلى نسبة تفعيل 100% في أقرب الآجال، وقد بلغت نسبة التفعيل 76% في نهاية سنة 2025.</p><p>نشكر جميع عملائنا وشركائنا على ثقتهم، ونتطلع إلى مزيد من التعاون المثمر.</p><p>والسلام عليكم ورحمة الله وبركاته</p><p><strong>عبد السلام بسيسة</strong><br>المدير العام</p>',
 '<h2>Mot du Directeur Général</h2><p>Mesdames, Messieurs,</p><p>J\'ai le plaisir de vous souhaiter la bienvenue sur le site officiel de la Société d\'Environnement, Plantation et Jardinage de Gabès.</p><p>Notre société, filiale du Groupe Chimique Tunisien, œuvre depuis sa création le 15 avril 2011 pour atteindre ses objectifs dans le domaine de l\'environnement et du développement durable dans la région de Gabès.</p><p>Nous travaillons d\'arrache-pied pour atteindre un taux d\'activation de 100% dans les plus brefs délais, et nous avons atteint 76% à la fin de l\'année 2025.</p><p>Nous remercions tous nos clients et partenaires pour leur confiance, et nous nous réjouissons d\'une collaboration plus fructueuse.</p><p><strong>Abdel Salam Besisse</strong><br>Directeur Général</p>',
 '<h2>Director\'s Message</h2><p>Ladies and Gentlemen,</p><p>It is my pleasure to welcome you to the official website of the Environment, Plantation and Gardening Company of Gabès.</p><p>Our company, a subsidiary of the Tunisian Chemical Group, has been working since its establishment on April 15, 2011 to achieve its goals in the field of environment and sustainable development in the Gabès region.</p><p>We are working hard to reach an activation rate of 100% as soon as possible, having reached 76% at the end of 2025.</p><p>We thank all our customers and partners for their trust, and we look forward to more fruitful collaboration.</p><p><strong>Abdel Salam Besisse</strong><br>General Director</p>',
 'published', 1, NOW(), NOW());

-- 4c. Board Meeting News - May 2026
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('post', 'board-meeting-may-2026',
 'اجتماع مجلس الإدارة - ماي 2026',
 'Conseil d\'administration - Mai 2026',
 'Board Meeting - May 2026',
 'اجتماع مجلس الإدارة يوم 25 ماي 2026 لمناقشة القوائم المالية لسنة 2025 والاستراتيجية المستقبلية للشركة.',
 'Réunion du conseil d\'administration le 25 mai 2026 pour discuter des états financiers 2025 et de la stratégie future de la société.',
 'Board of Directors meeting on May 25, 2026 to discuss the 2025 financial statements and the company\'s future strategy.',
 '<h2>اجتماع مجلس الإدارة</h2><p>عقد مجلس إدارة شركة البيئة والغراسة والبستنة بقابس اجتماعه الدوري يوم 25 ماي 2026.</p><h3>النقاط الرئيسية</h3><ul><li>مناقشة القوائم المالية لسنة 2025</li><li>عرض الإستراتيجية المستقبلية للشركة</li><li>بلغت نسبة التفعيل 76% في نهاية سنة 2025</li><li>الهدف هو الوصول إلى نسبة تفعيل 100%</li></ul><p>أشرف على الاجتماع السيد عبد السلام بسيسة المدير العام للشركة، بحضور أعضاء مجلس الإدارة.</p>',
 '<h2>Réunion du Conseil d\'administration</h2><p>Le Conseil d\'administration de la Société d\'Environnement, Plantation et Jardinage de Gabès a tenu sa réunion périodique le 25 mai 2026.</p><h3>Points principaux</h3><ul><li>Discussion des états financiers 2025</li><li>Présentation de la stratégie future de la société</li><li>Le taux d\'activation a atteint 76% à la fin de 2025</li><li>L\'objectif est d\'atteindre un taux d\'activation de 100%</li></ul><p>La réunion était présidée par M. Abdel Salam Besisse, Directeur Général de la société, en présence des membres du Conseil d\'administration.</p>',
 '<h2>Board of Directors Meeting</h2><p>The Board of Directors of the Environment, Plantation and Gardening Company of Gabès held its periodic meeting on May 25, 2026.</p><h3>Key Points</h3><ul><li>Discussion of the 2025 financial statements</li><li>Presentation of the company\'s future strategy</li><li>Activation rate reached 76% at the end of 2025</li><li>Goal is to reach 100% activation rate</li></ul><p>The meeting was chaired by Mr. Abdel Salam Besisse, General Director of the company, in the presence of Board members.</p>',
 'published', 1, '2026-05-25 10:00:00', NOW());

-- 4d. Olive Oil Initiative
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('post', 'olive-oil-initiative',
 'مبادرة بيع الزيتون مباشرة من مشروع منزل الحبيب',
 'Initiative de vente directe d\'huile d\'olive du projet Manzel El Habib',
 'Direct Olive Oil Sale Initiative from Manzel El Habib Project',
 'مبادرة لبيع زيت الزيتون مباشرة من مشروع منزل الحبيب بأسعار تنافسية.',
 'Initiative de vente directe d\'huile d\'olive à partir du projet Manzel El Habib à des prix compétitifs.',
 'Initiative to sell olive oil directly from the Manzel El Habib project at competitive prices.',
 '<h2>مبادرة بيع الزيتون مباشرة</h2><p>في إطار تعزيز التنمية المحلية، أطلقت شركة البيئة والغراسة والبستنة بقابس مبادرة لبيع زيت الزيتون مباشرة من مشروع منزل الحبيب.</p><p>تهدف هذه المبادرة إلى توفير زيت زيتون بجودة عالية وبأسعار تنافسية للمستهلكين.</p><p>للمزيد من المعلومات، يرجى الاتصال بإدارة الشركة.</p>',
 '<h2>Initiative de vente directe d\'huile d\'olive</h2><p>Dans le cadre de la promotion du développement local, la Société d\'Environnement, Plantation et Jardinage de Gabès a lancé une initiative de vente directe d\'huile d\'olive à partir du projet Manzel El Habib.</p><p>Cette initiative vise à fournir une huile d\'olive de haute qualité à des prix compétitifs aux consommateurs.</p><p>Pour plus d\'informations, veuillez contacter la direction de la société.</p>',
 '<h2>Direct Olive Oil Sale Initiative</h2><p>As part of promoting local development, the Environment, Plantation and Gardening Company of Gabès launched an initiative to sell olive oil directly from the Manzel El Habib project.</p><p>This initiative aims to provide high-quality olive oil at competitive prices to consumers.</p><p>For more information, please contact the company management.</p>',
 'published', 0, '2026-04-15 09:00:00', NOW());

-- 4e. Chenchou Sustainable Agriculture
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('project', 'chenchou-sustainable-agriculture',
 'شراكة الشنشو/OEP للفلاحة المستدامة',
 'Partenariat Chenchou/OEP pour l\'agriculture durable',
 'Chenchou/OEP Sustainable Agriculture Partnership',
 '10 هكتارات من المحاصيل العلفية في 2025 والتوسع بـ 5 هكتارات إضافية في 2026.',
 '10 hectares de cultures fourragères en 2025 et expansion de 5 hectares supplémentaires en 2026.',
 '10 hectares of forage crops in 2025 and expansion by 5 additional hectares in 2026.',
 '<h2>شراكة الشنشو/OEP للفلاحة المستدامة</h2><p>في إطار التعاون مع المعهد الوطني للزراعة (OEP)، أطلقت شركة البيئة والغراسة والبستنة بقابس مشروعا للفلاحة المستدامة في منطقة الشنشو.</p><h3>تفاصيل المشروع</h3><ul><li>10 هكتارات من المحاصيل العلفية في سنة 2025</li><li>التوسع بـ 5 هكتارات إضافية في سنة 2026</li><li>استعمال تقنيات الري الحديثة</li><li>تحسين جودة المحاصيل</li></ul>',
 '<h2>Partenariat Chenchou/OEP pour l\'agriculture durable</h2><p>Dans le cadre de la coopération avec l\'Office de l\'Élevage et des Pâturages (OEP), la Société d\'Environnement, Plantation et Jardinage de Gabès a lancé un projet d\'agriculture durable dans la région de Chenchou.</p><h3>Détails du projet</h3><ul><li>10 hectares de cultures fourragères en 2025</li><li>Expansion de 5 hectares supplémentaires en 2026</li><li>Utilisation de techniques d\'irrigation modernes</li><li>Amélioration de la qualité des cultures</li></ul>',
 '<h2>Chenchou/OEP Sustainable Agriculture Partnership</h2><p>As part of cooperation with the Livestock and Pastures Office (OEP), the Environment, Plantation and Gardening Company of Gabès launched a sustainable agriculture project in the Chenchou region.</p><h3>Project Details</h3><ul><li>10 hectares of forage crops in 2025</li><li>Expansion by 5 additional hectares in 2026</li><li>Use of modern irrigation techniques</li><li>Improvement of crop quality</li></ul>',
 'published', 1, '2025-12-01 10:00:00', NOW());

-- 4f. Green Belt Planting
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('activity', 'green-belt-planting',
 'غرس الحزام الأخضر: 400 شجرة Ficus vert',
 'Plantation de la ceinture verte : 400 Ficus vert',
 'Green Belt Planting: 400 Ficus vert Trees',
 'تم غرس 400 شجرة من نوع Ficus vert في إطار مشروع الحزام الأخضر بتاريخ 20 جانفي 2026.',
 'Plantation de 400 arbres Ficus vert dans le cadre du projet de ceinture verte le 20 janvier 2026.',
 '400 Ficus vert trees were planted as part of the green belt project on January 20, 2026.',
 '<h2>غرس الحزام الأخضر</h2><p>في إطار المشاريع البيئية للشركة، تم غرس 400 شجرة من نوع Ficus vert في 20 جانفي 2026.</p><p>هذه المبادرة تهدف إلى تعزيز الغطاء النباتي في المنطقة والمساهمة في تحسين جودة الهواء والبيئة.</p>',
 '<h2>Plantation de la ceinture verte</h2><p>Dans le cadre des projets environnementaux de la société, 400 arbres Ficus vert ont été plantés le 20 janvier 2026.</p><p>Cette initiative vise à renforcer la couverture végétale dans la région et à contribuer à l\'amélioration de la qualité de l\'air et de l\'environnement.</p>',
 '<h2>Green Belt Planting</h2><p>As part of the company\'s environmental projects, 400 Ficus vert trees were planted on January 20, 2026.</p><p>This initiative aims to strengthen vegetation cover in the region and contribute to improving air quality and the environment.</p>',
 'published', 1, '2026-01-20 14:00:00', NOW());

-- 4g. Bouchemma Cleaning Intervention
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('activity', 'bouchemma-cleaning',
 'تدخل تنظيف بوشمة',
 'Intervention de nettoyage à Bouchemma',
 'Cleaning Intervention in Bouchemma',
 'تدخل تنظيف في منطقة بوشمة بتاريخ 9 جانفي 2026.',
 'Intervention de nettoyage dans la région de Bouchemma le 9 janvier 2026.',
 'Cleaning intervention in the Bouchemma area on January 9, 2026.',
 '<h2>تدخل تنظيف بوشمة</h2><p>في إطار المسؤولية المجتمعية للشركة، قامت شركة البيئة والغراسة والبستنة بقابس بتدخل نظافة في منطقة بوشمة بتاريخ 9 جانفي 2026.</p><p>شمل التدخل تنظيف الأماكن العامة والطرقات، بمشاركة أعوان الشركة.</p>',
 '<h2>Intervention de nettoyage à Bouchemma</h2><p>Dans le cadre de la responsabilité sociétale de la société, la Société d\'Environnement, Plantation et Jardinage de Gabès a effectué une intervention de nettoyage dans la région de Bouchemma le 9 janvier 2026.</p><p>L\'intervention a inclus le nettoyage des lieux publics et des routes, avec la participation des agents de la société.</p>',
 '<h2>Cleaning Intervention in Bouchemma</h2><p>As part of the company\'s social responsibility, the Environment, Plantation and Gardening Company of Gabès carried out a cleaning intervention in the Bouchemma area on January 9, 2026.</p><p>The intervention included cleaning public places and roads, with the participation of company agents.</p>',
 'published', 0, '2026-01-09 08:00:00', NOW());

