INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('activity', 'saniet-el-bey-intervention',
 'تدخل بالمركب الشبابي سانية الباي',
 'Intervention au complexe des jeunes Saniet El Bey',
