-- 4j. Sports and Work Page
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('sport', 'sports-and-work',
 'الرياضة والعمل',
 'Sports et Travail',
 'Sports & Work',
 'الأنشطة الرياضية للشركة: فرق كرة القدم +40 و-40، الكرة الطائرة للنساء، البيتانك للرجال.',
 'Activités sportives de la société : équipes de football +40 et -40, volley-ball féminin, pétanque masculine.',
 'Company sports activities: football teams +40 and -40, women\'s volleyball, men\'s pétanque.',
 '<h2>الرياضة والعمل</h2><p>تولي شركة البيئة والغراسة والبستنة بقابس أهمية كبيرة للأنشطة الرياضية كجزء من ثقافة المؤسسة.</p><h3>الفرق الرياضية</h3><ul><li>فريق كرة القدم +40</li><li>فريق كرة القدم -40</li><li>فريق الكرة الطائرة للنساء</li><li>فريق البيتانك للرجال</li></ul><h3>الإنجازات</h3><p>تحصلت الفرق الرياضية للشركة على عدة تتويجات في البطولات المحلية والجهوية، مما يعكس الروح الرياضية العالية لدى أعوان الشركة.</p>',
 '<h2>Sports et Travail</h2><p>La Société d\'Environnement, Plantation et Jardinage de Gabès accorde une grande importance aux activités sportives dans le cadre de sa culture d\'entreprise.</p><h3>Équipes sportives</h3><ul><li>Équipe de football +40</li><li>Équipe de football -40</li><li>Équipe de volley-ball féminin</li><li>Équipe de pétanque masculine</li></ul><h3>Réalisations</h3><p>Les équipes sportives de la société ont remporté plusieurs distinctions dans les championnats locaux et régionaux, reflétant l\'esprit sportif élevé des agents de la société.</p>',
 '<h2>Sports & Work</h2><p>The Environment, Plantation and Gardening Company of Gabès places great importance on sports activities as part of its corporate culture.</p><h3>Sports Teams</h3><ul><li>Football team +40</li><li>Football team -40</li><li>Women\'s volleyball team</li><li>Men\'s pétanque team</li></ul><h3>Achievements</h3><p>The company\'s sports teams have won several awards in local and regional championships, reflecting the high sportsmanship of the company\'s employees.</p>',
 'published', 1, NOW(), NOW());

-- 4k. Resources and Development Page
INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('resource', 'resources-and-development',
 'الموارد والتنمية',
 'Ressources et Développement',
 'Resources & Development',
 'الدراسات والتكوين والتدريب والري الذكي وإنترنت الأشياء والموارد البشرية والمحاسبة والمالية والإعلامية.',
 'Études, formation, stages, irrigation intelligente, IoT, RH, finances, comptabilité, informatique.',
 'Studies, training, internships, smart irrigation, IoT, HR, finance, accounting, IT.',
 '<h2>الموارد والتنمية</h2><p>تعمل شركة البيئة والغراسة والبستنة بقابس على تطوير مواردها البشرية والتقنية لتحقيق أفضل النتائج.</p><h3>مجالات التطوير</h3><ul><li>الدراسات والأبحاث في مجال البيئة</li><li>التكوين والتدريب المستمر للأعوان</li><li>برامج التدريب والتطوير المهني</li><li>الري الذكي باستخدام تقنيات حديثة</li><li>إنترنت الأشياء (IoT) في الزراعة</li><li>صندوق الحماية الذكي</li><li>الحاجز الأوتوماتيكي</li></ul><h3>الإدارات</h3><ul><li>الموارد البشرية</li><li>المسؤولية المجتمعية (RSE)</li><li>المالية والمحاسبة</li><li>الإعلامية</li><li>الهندسة الفلاحية</li><li>السلامة الصناعية</li></ul>',
 '<h2>Ressources et Développement</h2><p>La Société d\'Environnement, Plantation et Jardinage de Gabès œuvre pour développer ses ressources humaines et techniques afin d\'obtenir les meilleurs résultats.</p><h3>Domaines de développement</h3><ul><li>Études et recherches environnementales</li><li>Formation continue des agents</li><li>Programmes de stages et développement professionnel</li><li>Irrigation intelligente utilisant des technologies modernes</li><li>Internet des objets (IoT) en agriculture</li><li>Boîtier de garde intelligent</li><li>Barrière automatique</li></ul><h3>Services</h3><ul><li>Ressources humaines</li><li>Responsabilité Sociétale d\'Entreprise (RSE)</li><li>Finances et comptabilité</li><li>Informatique</li><li>Génie agricole</li><li>Sécurité industrielle</li></ul>',
 '<h2>Resources & Development</h2><p>The Environment, Plantation and Gardening Company of Gabès works to develop its human and technical resources to achieve the best results.</p><h3>Development Areas</h3><ul><li>Studies and research in the environmental field</li><li>Continuous training for employees</li><li>Internship and professional development programs</li><li>Smart irrigation using modern technologies</li><li>Internet of Things (IoT) in agriculture</li><li>Smart guard box</li><li>Automatic barrier</li></ul><h3>Departments</h3><ul><li>Human Resources</li><li>Corporate Social Responsibility (CSR)</li><li>Finance and Accounting</li><li>Information Technology</li><li>Agricultural Engineering</li><li>Industrial Safety</li></ul>',
 'published', 1, NOW(), NOW());

