INSERT INTO `content_items` (`type`, `slug`, `title_ar`, `title_fr`, `title_en`, `summary_ar`, `summary_fr`, `summary_en`, `body_ar`, `body_fr`, `body_en`, `status`, `is_featured`, `published_at`, `created_at`) VALUES
('prize', 'sports-championship-2025',
 'بطولة الرياضة والعمل 2025',
 'Championnat Sports et Travail 2025',
 'Sports & Work Championship 2025',
 'تحصل فريق كرة القدم -40 على المرتبة الأولى في بطولة الرياضة والعمل 2025.',
 'L\'équipe de football -40 a remporté la première place au championnat Sports et Travail 2025.',
 'The football team -40 won first place in the Sports & Work Championship 2025.',
 '<h2>بطولة الرياضة والعمل 2025</h2><p>فاز فريق كرة القدم -40 لشركة البيئة والغراسة والبستنة بقابس بالمرتبة الأولى في بطولة الرياضة والعمل 2025.</p><p>هذا الإنجاز يعكس الروح الرياضية العالية والالتزام لدى أعوان الشركة.</p>',
 '<h2>Championnat Sports et Travail 2025</h2><p>L\'équipe de football -40 de la Société d\'Environnement, Plantation et Jardinage de Gabès a remporté la première place au championnat Sports et Travail 2025.</p><p>Cette réalisation reflète l\'esprit sportif élevé et l\'engagement des agents de la société.</p>',
 '<h2>Sports & Work Championship 2025</h2><p>The football team -40 of the Environment, Plantation and Gardening Company of Gabès won first place in the Sports & Work Championship 2025.</p><p>This achievement reflects the high sportsmanship and commitment of the company\'s employees.</p>',
 'published', 1, NOW(), NOW());